import{_ as n,r as o,o as i,c as s,b as e,d as a,a as c,e as r}from"./app.0a43b3c6.js";const l={},d=c('<h1 id="understanding-process-nexttick" tabindex="-1"><a class="header-anchor" href="#understanding-process-nexttick" aria-hidden="true">#</a> Understanding Process.nextTick()</h1><ul><li>Every time the event loop takes a full trip, we call it a tick.</li><li>When we pass a function to <code>process.nextTick()</code>, we instruct the engine to invoke this function at the end of the current operation, before the next event loop tick starts.</li><li>It&#39;s the way we can tell the JS engine to process a function asynchronously (after the current function), but as soon as possible, not queue it.</li><li>Calling <code>setTimeout(() =&gt; {}, 0)</code> will execute the function at the end of next tick, much later than when using <code>nextTick()</code> which prioritizes the call and executes it just before the beginning of the next tick.</li><li>Use <code>nextTick()</code> when you want to make sure that in the next event loop iteration that code is already executed.</li></ul><h2 id="refs" tabindex="-1"><a class="header-anchor" href="#refs" aria-hidden="true">#</a> Refs</h2>',3),h={href:"https://nodejs.dev/en/learn/understanding-processnexttick/",target:"_blank",rel:"noopener noreferrer"},u=r("Understanding Process.nextTick()");function f(x,_){const t=o("ExternalLinkIcon");return i(),s("div",null,[d,e("ul",null,[e("li",null,[e("a",h,[u,a(t)])])])])}const k=n(l,[["render",f],["__file","understanding_process_nexttick.html.vue"]]);export{k as default};
